var s=class{static KICKBASE_API_URL="https://api.kickbase.com/v4";static PATH_DELIMITER="/";static USER_PATH="user";static LOGIN_PATH="login";static LEAGUES_PATH="leagues";static SQUAD_PATH="squad";static PLAYERS_PATH="players";static MARKET_PATH="market";static MANAGERS_PATH="managers";static DASHBOARD_PATH="dashboard";static PERFORMANCE_PATH="performance";static ME_PATH="me";static BUDGET_PATH="budget";static OFFERS_PATH="offers";static CURRENT_SEASON_PERFORMANCE_NAME="2025/2026";static loginUrl(){return this.buildApiUrl([this.USER_PATH,this.LOGIN_PATH])}static mySquadUrl(t){return this.buildApiUrl([this.LEAGUES_PATH,t,this.SQUAD_PATH])}static marketUrl(t){return this.buildApiUrl([this.LEAGUES_PATH,t,this.MARKET_PATH])}static playerInformationUrl(t,i){return this.buildApiUrl([this.LEAGUES_PATH,t,this.PLAYERS_PATH,i])}static playerPerformanceUrl(t,i){return this.buildApiUrl([this.LEAGUES_PATH,t,this.PLAYERS_PATH,i,this.PERFORMANCE_PATH])}static placeOfferUrl(t,i){return this.buildApiUrl([this.LEAGUES_PATH,t,this.MARKET_PATH,i,this.OFFERS_PATH])}static withDrawOfferUrl(t,i,r){return this.buildApiUrl([this.LEAGUES_PATH,t,this.MARKET_PATH,i,this.OFFERS_PATH,r])}static managerDashboardUrl(t,i){return this.buildApiUrl([this.LEAGUES_PATH,t,this.MANAGERS_PATH,i,this.DASHBOARD_PATH])}static managerBudgetUrl(t){return this.buildApiUrl([this.LEAGUES_PATH,t,this.ME_PATH,this.BUDGET_PATH])}static buildApiUrl(t){let i=this.KICKBASE_API_URL;for(let r of t)i+=this.prefixWithDelimiter(r);return i}static prefixWithDelimiter(t){return this.PATH_DELIMITER+t}};export{s as a};
